  // 2. Normalize the target (channel or nick)
  // 3. Connect to IRC client (or reuse existing connection)
  // 4. Split text according to textChunkLimit (default 350 chars)
  // 5. Send each chunk via PRIVMSG
  // 6. Return { messageId, target }

  // Example stub:
  const messageId = `irc-${Date.now()}`;
  const normalizedTarget = normalizeIrcMessagingTarget(to);
  if (!normalizedTarget) {
    throw new Error(`Invalid IRC target: ${to}`);
