### Step 7: `src/types.ts`

Defines the config and resolved-account shapes:

```typescript
import type { DmPolicy, GroupPolicy, MarkdownConfig } from "openclaw/plugin-sdk/channel-config-primitives";
import type { SecretInput } from "openclaw/plugin-sdk/secret-input";
import type { OpenClawConfig } from "../api.js";

export interface PulseBoardAccountConfig {
  enabled?: boolean;
  name?: string;
  apiKey?: SecretInput;        // PulseBoard API key
  userId?: string;             // Optional override; resolved from API key at runtime
  dmPolicy?: DmPolicy;
  allowFrom?: Array<string | number>;
  groupPolicy?: GroupPolicy;
  groupAllowFrom?: Array<string | number>;
  boards?: Record<string, PulseBoardBoardConfig>; // per-board overrides
  markdown?: MarkdownConfig;
  textChunkLimit?: number;
}

export interface PulseBoardBoardConfig {
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  requireMention?: boolean;
  systemPrompt?: string;
}

export type PulseBoardConfig = PulseBoardAccountConfig & {
  defaultAccount?: string;
};

export interface ResolvedPulseBoardAccount {
  accountId: string;
  name?: string;
  enabled: boolean;
  configured: boolean;
  apiKey: string;
  userId: string;
  config: PulseBoardAccountConfig;
}

export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

export interface PulseBoardInboundMessage {
  messageId: string;
  boardId?: string;      // Set for board (group) messages; absent for DMs
  senderId: string;
  senderName?: string;
  text: string;
  timestamp: number;
  isBoard: boolean;      // true = board message, false = DM
}
```

### Step 8: `src/config-schema.ts`

