 * This is a stub — in a real implementation it would open a WebSocket.
 */
export async function connectPulseBoard(opts: {
  apiKey: string;
  onMessage: PulseBoardMessageHandler;
  onError: PulseBoardErrorHandler;
  onConnect: () => void;
  onDisconnect: () => void;
