### Step 15: `src/channel.ts`

Main `createChatChannelPlugin()` call:

```typescript
import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";
import { describeAccountSnapshot } from "openclaw/plugin-sdk/account-helpers";
import {
  createTopLevelChannelConfigAdapter,
  createScopedDmSecurityResolver,
} from "openclaw/plugin-sdk/channel-config-helpers";
import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import { buildPassiveChannelStatusSummary, buildTrafficStatusSummary, runStoppablePassiveMonitor } from "openclaw/plugin-sdk/extension-shared";
import { createComputedAccountStatusAdapter } from "openclaw/plugin-sdk/status-helpers";
import { createChannelPairingController } from "openclaw/plugin-sdk/channel-pairing";
// ... etc.

export const pulseBoardPlugin = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: { id: "pulseboard", label: "PulseBoard", selectionLabel: "PulseBoard", ... },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
      blockStreaming: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    configSchema: buildChannelConfigSchema(PulseBoardConfigSchema),
    setup: pulseBoardSetupAdapter,
    setupWizard: pulseBoardSetupWizard,
    config: {
      ...pulseBoardConfigAdapter,           // createTopLevelChannelConfigAdapter result
      isConfigured: (account) => account.configured,
      describeAccount: (account) => describeAccountSnapshot({ account, configured: account.configured, extra: { userId: account.userId } }),
    },
    messaging: {
      normalizeTarget: normalizePulseBoardTarget,
      targetResolver: {
        looksLikeId: looksLikePulseBoardId,
        hint: "<userId|board:boardName>",
      },
    },
    groups: {
      resolveRequireMention: ({ cfg, accountId, groupId }) => { ... }, // default true
      resolveToolPolicy: ({ cfg, accountId, groupId }) => { ... },
    },
    status: createComputedAccountStatusAdapter<ResolvedPulseBoardAccount>({
      defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
      collectStatusIssues: (accounts) => collectStatusIssuesFromLastError("pulseboard", accounts),
      buildChannelSummary: ({ snapshot }) =>
        buildPassiveChannelStatusSummary(snapshot, { userId: snapshot.userId ?? null }),
      resolveAccountSnapshot: ({ account, runtime }) => ({
        accountId: account.accountId,
        name: account.name,
        enabled: account.enabled,
        configured: account.configured,
        extra: { userId: account.userId, ...buildTrafficStatusSummary(runtime) },
      }),
    }),
    gateway: {
      startAccount: async (ctx) => {
        const account = ctx.account;
        if (!account.configured) throw new Error("PulseBoard API key not configured.");
        ctx.log?.info(`[${account.accountId}] starting PulseBoard provider (userId: ${account.userId})`);
        const runtime = getPulseBoardRuntime();
        await runStoppablePassiveMonitor({
          abortSignal: ctx.abortSignal,
          start: async () =>
            await monitorPulseBoardProvider({
              accountId: account.accountId,
              config: ctx.cfg as CoreConfig,
              runtime,
              abortSignal: ctx.abortSignal,
            }),
        });
      },
    },
  },
  pairing: {
    text: {
      idLabel: "pulseBoardUser",
      message: PAIRING_APPROVED_MESSAGE,
      normalizeAllowEntry: (entry) => normalizePulseBoardAllowEntry(entry),
      notify: async ({ id, message }) => {
        await sendMessagePulseBoard(id, message);
      },
    },
  },
  security: {
    resolveDmPolicy: resolvePulseBoardDmPolicy,  // createScopedDmSecurityResolver result
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ cfg, to, text, accountId }) => {
      return sendMessagePulseBoard(to, text ?? "", {
        cfg: cfg as CoreConfig,
        accountId: accountId ?? undefined,
      });
    },
  },
});
```

