### Step 12: `src/send.ts`

```typescript
import type { CoreConfig } from "./types.js";
import { getPulseBoardRuntime } from "./runtime.js";
import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/routing";
import { isBoardTarget, normalizePulseBoardTarget } from "./normalize.js";

// Map of active client handles keyed by accountId
export const activeClients = new Map<string, PulseBoardClientHandle>();

export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: { cfg?: CoreConfig; accountId?: string } = {},
): Promise<{ to: string; messageId: string }> {
  const accountId = opts.accountId ?? DEFAULT_ACCOUNT_ID;
  const client = activeClients.get(accountId);
  if (!client) throw new Error(`PulseBoard client not running for account ${accountId}`);

  const normalized = normalizePulseBoardTarget(to);
  if (!normalized) throw new Error(`Invalid PulseBoard target: ${to}`);

  const runtime = getPulseBoardRuntime();
  const tableMode = runtime.channel.text.resolveMarkdownTableMode({
    cfg: opts.cfg ?? ({} as CoreConfig),
    channel: "pulseboard",
    accountId,
  });
  const message = runtime.channel.text.convertMarkdownTables(text ?? "", tableMode);

  let messageId: string;
  if (isBoardTarget(normalized)) {
    const result = await client.postToBoard(normalized, message);
    messageId = result.messageId;
  } else {
    const result = await client.sendDm(normalized, message);
    messageId = result.messageId;
  }

  return attachChannelToResult("pulseboard", { to: normalized, messageId });
}
```

### Step 13: `src/monitor.ts`

The gateway loop. Handles both DM and board inbound events:

```typescript
import { dispatchInboundDirectDmWithRuntime } from "openclaw/plugin-sdk/direct-dm";
import { dispatchInboundReplyWithBase } from "../runtime-api.js";
import { createChannelPairingController } from "openclaw/plugin-sdk/channel-pairing";
import { resolveInboundDirectDmAccessWithRuntime } from "openclaw/plugin-sdk/direct-dm";
import { connectPulseBoard } from "./client.js";
import { activeClients } from "./send.js";
import { normalizePulseBoardAllowEntry, isBoardTarget } from "./normalize.js";
// ... etc.

export async function monitorPulseBoardProvider(params: {
  accountId: string;
  config: CoreConfig;
  runtime: PluginRuntime;
  abortSignal: AbortSignal;
}): Promise<void> {
  const { accountId, config, runtime, abortSignal } = params;
  const account = resolvePulseBoardAccount({ cfg: config, accountId });

  const pairing = createChannelPairingController({
    core: runtime,
    channel: "pulseboard",
    accountId,
  });

  const client = await connectPulseBoard({
    apiKey: account.apiKey,
    abortSignal,
    onConnect: () => { /* log */ },
    onDisconnect: () => { /* log */ },
    onError: (err, ctx) => { /* log */ },
    onMessage: async (event) => {
      if (event.type === "dm") {
        // DM inbound: use dispatchInboundDirectDmWithRuntime
        const access = await resolveInboundDirectDmAccessWithRuntime({ ... });
        if (access.access.decision !== "allow") return;
        await dispatchInboundDirectDmWithRuntime({
          cfg: config,
          runtime,
          channel: "pulseboard",
          channelLabel: "PulseBoard",
          accountId,
          peer: { kind: "direct", id: event.senderId },
          senderId: event.senderId,
          senderAddress: `pulseboard:${event.senderId}`,
          recipientAddress: `pulseboard:${account.userId}`,
          conversationLabel: event.senderName ?? event.senderId,
          rawBody: event.text,
          messageId: event.messageId,
          timestamp: event.timestamp,
          commandAuthorized: access.commandAuthorized,
          deliver: async (payload) => {
            const text = extractText(payload);
            if (text?.trim()) await client.sendDm(event.senderId, text);
          },
          onRecordError: (err) => { /* log */ },
          onDispatchError: (err, info) => { /* log */ },
        });
      } else {
        // Board (group) inbound: use dispatchInboundReplyWithBase
        await dispatchInboundReplyWithBase({
          cfg: config,
          runtime,
          channel: "pulseboard",
          channelLabel: "PulseBoard",
          accountId,
          peer: { kind: "group", id: event.boardId! },
          senderId: event.senderId,
          senderAddress: `pulseboard:${event.senderId}`,
          conversationLabel: event.boardId!,
          rawBody: event.text,
          messageId: event.messageId,
          timestamp: event.timestamp,
          deliver: async (payload) => {
            const text = extractText(payload);
            if (text?.trim()) await client.postToBoard(event.boardId!, text);
          },
          onRecordError: (err) => { /* log */ },
          onDispatchError: (err, info) => { /* log */ },
        });
      }
    },
  });

  activeClients.set(accountId, client);
  // wait for abort
  await new Promise<void>((resolve) => {
    abortSignal.addEventListener("abort", () => {
      client.close();
      activeClients.delete(accountId);
      resolve();
    });
  });
}
```

