import {
  DEFAULT_ACCOUNT_ID,
  normalizeAccountId,
  normalizeOptionalAccountId,
} from "openclaw/plugin-sdk/account-id";
import {
  listCombinedAccountIds,
  resolveListedDefaultAccountId,
} from "openclaw/plugin-sdk/account-resolution";
import { normalizeSecretInputString, type SecretInput } from "openclaw/plugin-sdk/secret-input";
import type { OpenClawConfig } from "../api.js";

/** Per-board configuration overrides. */
export interface PulseBoardBoardConfig {
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  requireMention?: boolean;
  systemPrompt?: string;
}

/** Top-level channels.pulseboard configuration shape. */
export interface PulseBoardAccountConfig {
  enabled?: boolean;
  name?: string;
  defaultAccount?: string;
  /** PulseBoard API key (SecretInput — can be a literal or env-var reference). */
  apiKey?: SecretInput;
  /** Optional userId override; derived from the API key at runtime when absent. */
  userId?: string;
  /** DM access policy. Defaults to "pairing". */
  dmPolicy?: "pairing" | "allowlist" | "open" | "disabled";
  allowFrom?: Array<string | number>;
  /** Board access policy. Defaults to "allowlist". */
  groupPolicy?: "open" | "disabled" | "allowlist";
  groupAllowFrom?: Array<string | number>;
  /** Per-board configuration keyed by board ID (slug). */
  boards?: Record<string, PulseBoardBoardConfig>;
  markdown?: { tables?: "plain" | "ascii" | "html" };
  textChunkLimit?: number;
}

export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardAccountConfig;
  };
};

/** Resolved runtime account snapshot. */
export interface ResolvedPulseBoardAccount {
  accountId: string;
  name?: string;
  enabled: boolean;
  configured: boolean;
  /** Resolved raw API key string (empty when not configured). */
  apiKey: string;
  /** Resolved userId derived from or overriding the API key. */
  userId: string;
  config: PulseBoardAccountConfig;
}

/** Inbound message from the PulseBoard platform. */
export interface PulseBoardInboundMessage {
  messageId: string;
  /** Set for board (group) messages; absent for DMs. */
  boardId?: string;
  senderId: string;
  senderName?: string;
  text: string;
  timestamp: number;
  /** true when this is a board post; false when it is a DM. */
  isBoard: boolean;
}

// ── Account resolution helpers ──────────────────────────────────────

function resolveConfiguredDefaultPulseBoardAccountId(cfg: OpenClawConfig): string | undefined {
  const pbCfg = (cfg.channels as Record<string, unknown> | undefined)?.pulseboard as
    | PulseBoardAccountConfig
    | undefined;
  return normalizeOptionalAccountId(pbCfg?.defaultAccount);
}

/**
 * List all configured PulseBoard account IDs.
 * PulseBoard uses a single top-level account, so returns ["default"] when configured.
 */
export function listPulseBoardAccountIds(cfg: OpenClawConfig): string[] {
  const pbCfg = (cfg.channels as Record<string, unknown> | undefined)?.pulseboard as
    | PulseBoardAccountConfig
    | undefined;
  const apiKey = normalizeSecretInputString(pbCfg?.apiKey);
  return listCombinedAccountIds({
    configuredAccountIds: [],
    implicitAccountId: apiKey
      ? (resolveConfiguredDefaultPulseBoardAccountId(cfg) ?? DEFAULT_ACCOUNT_ID)
      : undefined,
  });
}

/** Get the default PulseBoard account ID. */
export function resolveDefaultPulseBoardAccountId(cfg: OpenClawConfig): string {
  return resolveListedDefaultAccountId({
    accountIds: listPulseBoardAccountIds(cfg),
    configuredDefaultAccountId: resolveConfiguredDefaultPulseBoardAccountId(cfg),
  });
}

/**
 * Resolve a PulseBoard account from config.
 * Derives a userId from the API key when no explicit override is provided.
 */
export function resolvePulseBoardAccount(opts: {
  cfg: OpenClawConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const accountId = normalizeAccountId(
    opts.accountId ?? resolveDefaultPulseBoardAccountId(opts.cfg),
  );
  const pbCfg = (opts.cfg.channels as Record<string, unknown> | undefined)?.pulseboard as
    | PulseBoardAccountConfig
    | undefined;

  const enabled = pbCfg?.enabled !== false;
  const apiKey = normalizeSecretInputString(pbCfg?.apiKey) ?? "";
  const configured = Boolean(apiKey);

  // Derive a stable userId from the API key prefix when no explicit override is set.
  const userId =
    pbCfg?.userId?.trim() ||
    (apiKey ? `pb-${apiKey.slice(0, 8).toLowerCase().replace(/[^a-z0-9]/g, "")}` : "");

  return {
    accountId,
    name: pbCfg?.name?.trim() || undefined,
    enabled,
    configured,
    apiKey,
    userId,
    config: {
      enabled: pbCfg?.enabled,
      name: pbCfg?.name,
      defaultAccount: pbCfg?.defaultAccount,
      apiKey: pbCfg?.apiKey,
      userId: pbCfg?.userId,
      dmPolicy: pbCfg?.dmPolicy,
      allowFrom: pbCfg?.allowFrom,
      groupPolicy: pbCfg?.groupPolicy,
      groupAllowFrom: pbCfg?.groupAllowFrom,
      boards: pbCfg?.boards,
      markdown: pbCfg?.markdown,
      textChunkLimit: pbCfg?.textChunkLimit,
    },
  };
}

