import {
  AllowFromListSchema,
  buildChannelConfigSchema,
  DmPolicySchema,
  GroupPolicySchema,
  MarkdownConfigSchema,
  ReplyRuntimeConfigSchemaShape,
} from "openclaw/plugin-sdk/channel-config-primitives";
import { buildSecretInputSchema } from "openclaw/plugin-sdk/secret-input";
import { z } from "openclaw/plugin-sdk/zod";

/** Per-board Zod schema. */
const PulseBoardBoardSchema = z
  .object({
    enabled: z.boolean().optional(),
    allowFrom: AllowFromListSchema,
    requireMention: z.boolean().optional(),
    systemPrompt: z.string().optional(),
  })
  .strict();

/** Full Zod schema for channels.pulseboard.* configuration. */
export const PulseBoardConfigSchema = z
  .object({
    /** Whether this channel is enabled. */
    enabled: z.boolean().optional(),

    /** Optional display name for this account. */
    name: z.string().optional(),

    /** Optional default account id for routing. */
    defaultAccount: z.string().optional(),

    /** PulseBoard API key (literal or env-var reference). */
    apiKey: buildSecretInputSchema().optional(),

    /** Optional userId override; derived from the API key when absent. */
    userId: z.string().optional(),

    /** DM access policy. Defaults to "pairing". */
    dmPolicy: DmPolicySchema.optional(),

    /** Allowed DM sender IDs. */
    allowFrom: AllowFromListSchema,

    /** Board access policy. Defaults to "allowlist". */
    groupPolicy: GroupPolicySchema.optional(),

    /** Allowed board sender IDs (used when groupPolicy is "allowlist"). */
    groupAllowFrom: AllowFromListSchema,

    /** Per-board configuration keyed by board ID slug. */
    boards: z.record(z.string(), PulseBoardBoardSchema.optional()).optional(),

    /** Markdown table rendering overrides. */
    markdown: MarkdownConfigSchema,

    ...ReplyRuntimeConfigSchemaShape,
  })
  .strict();

export type PulseBoardConfig = z.infer<typeof PulseBoardConfigSchema>;

/**
 * JSON Schema for Control UI (converted from Zod).
 */
export const pulseBoardChannelConfigSchema = buildChannelConfigSchema(PulseBoardConfigSchema);

