 * @param opts.onConnect    - Called once the connection is established.
 * @param opts.onDisconnect - Called when the connection drops.
 * @param opts.abortSignal  - When aborted the connection is closed gracefully.
 */
export async function connectPulseBoard(opts: {
  apiKey: string;
  onMessage: PulseBoardMessageHandler;
  onError: PulseBoardErrorHandler;
  onConnect: () => void;
  onDisconnect: () => void;
