import {
  createPreCryptoDirectDmAuthorizer,
  dispatchInboundDirectDmWithRuntime,
  resolveInboundDirectDmAccessWithRuntime,
} from "openclaw/plugin-sdk/direct-dm";
import { createChannelPairingController } from "openclaw/plugin-sdk/channel-pairing";
import { dispatchInboundReplyWithBase } from "../runtime-api.js";
import { connectPulseBoard, type PulseBoardMessageEvent } from "./client.js";
import { normalizePulseBoardAllowEntry } from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import { activeClients } from "./send.js";
import { resolvePulseBoardAccount, type CoreConfig, type PluginRuntime } from "./types.js";

// Re-export PluginRuntime so types.ts can use it through the api barrel.
export type { PluginRuntime };

// ── Sender allowlist helper ───────────────────────────────────────────

function isPulseBoardSenderAllowed(senderId: string, allowFrom: string[]): boolean {
  const normalizedSender = senderId.trim().toLowerCase();
  for (const entry of allowFrom) {
    const normalized = normalizePulseBoardAllowEntry(String(entry));
    if (normalized === "*" || normalized === normalizedSender) {
      return true;
    }
  }
  return false;
}

// ── Board inbound helper ──────────────────────────────────────────────

async function handleBoardInbound(params: {
  event: PulseBoardMessageEvent & { type: "board" };
  accountId: string;
  cfg: CoreConfig;
  deliver: (boardId: string, text: string) => Promise<void>;
}): Promise<void> {
  const { event, accountId, cfg } = params;
  const boardId = event.boardId ?? "unknown";
  const rawBody = event.text?.trim() ?? "";
  if (!rawBody) {
    return;
  }

  const core = getPulseBoardRuntime();

  // Resolve the outbound session route for this board.
  const route = core.channel.routing.resolveAgentRoute({
    cfg,
    channel: "pulseboard",
    accountId,
    peer: { kind: "group", id: boardId },
  });

  const storePath = core.channel.session.resolveStorePath(cfg.session?.store, {
    agentId: route.agentId,
  });

  const previousTimestamp = core.channel.session.readSessionUpdatedAt({
    storePath,
    sessionKey: route.sessionKey,
  });

  const envelopeOptions = core.channel.reply.resolveEnvelopeFormatOptions(cfg);
  const body = core.channel.reply.formatAgentEnvelope({
    channel: "PulseBoard",
    from: boardId,
    timestamp: event.timestamp,
    previousTimestamp,
    envelope: envelopeOptions,
    body: rawBody,
  });

  const ctxPayload = core.channel.reply.finalizeInboundContext({
    Body: body,
    RawBody: rawBody,
    CommandBody: rawBody,
    From: `pulseboard:board:${boardId}`,
    To: `pulseboard:board:${boardId}`,
    SessionKey: route.sessionKey,
    AccountId: accountId,
    ChatType: "group",
    ConversationLabel: boardId,
    SenderName: event.senderName || undefined,
    SenderId: event.senderId,
    GroupSubject: boardId,
    Provider: "pulseboard",
    Surface: "pulseboard",
    MessageSid: event.messageId,
    Timestamp: event.timestamp,
    OriginatingChannel: "pulseboard",
    OriginatingTo: `pulseboard:board:${boardId}`,
  });

  await dispatchInboundReplyWithBase({
    cfg,
    channel: "pulseboard",
    accountId,
    route,
    storePath,
    ctxPayload,
    core,
    deliver: async (payload) => {
      const outboundText =
        payload && typeof payload === "object" && "text" in payload
          ? String((payload as { text?: string }).text ?? "")
          : "";
      if (outboundText.trim()) {
        await params.deliver(boardId, outboundText);
      }
    },
    onRecordError: (err) => {
      core.logging
        .getChildLogger()
        .error(`[${accountId}] PulseBoard: failed recording board session: ${String(err)}`);
    },
    onDispatchError: (err, info) => {
      core.logging
        .getChildLogger()
        .error(`[${accountId}] PulseBoard: board ${info.kind} reply failed: ${String(err)}`);
    },
  });
}

// ── Main monitor ──────────────────────────────────────────────────────

export async function monitorPulseBoardProvider(params: {
  accountId: string;
  config: CoreConfig;
  abortSignal: AbortSignal;
}): Promise<void> {
  const { accountId, config, abortSignal } = params;
  const account = resolvePulseBoardAccount({ cfg: config, accountId });
  const runtime = getPulseBoardRuntime();

  const pairing = createChannelPairingController({
    core: runtime,
    channel: "pulseboard",
    accountId,
  });

  const resolveInboundAccess = async (senderId: string, rawBody: string) =>
    resolveInboundDirectDmAccessWithRuntime({
      cfg: config,
      channel: "pulseboard",
      accountId,
      dmPolicy: account.config.dmPolicy ?? "pairing",
      allowFrom: account.config.allowFrom,
      senderId,
      rawBody,
      isSenderAllowed: isPulseBoardSenderAllowed,
      runtime: {
        shouldComputeCommandAuthorized:
          runtime.channel.commands.shouldComputeCommandAuthorized,
        resolveCommandAuthorizedFromAuthorizers:
          runtime.channel.commands.resolveCommandAuthorizedFromAuthorizers,
      },
    });

  const authorizeSender = createPreCryptoDirectDmAuthorizer({
    resolveAccess: async (senderId) => await resolveInboundAccess(senderId, ""),
    issuePairingChallenge: async ({ senderId, reply }) => {
      await pairing.issueChallenge({
        senderId,
        senderIdLine: `Your PulseBoard user ID: ${senderId}`,
        sendPairingReply: reply,
        onCreated: () => {
          runtime.logging
            .getChildLogger()
            .debug?.(`[${accountId}] PulseBoard pairing request sender=${senderId}`);
        },
        onReplyError: (err) => {
          runtime.logging
            .getChildLogger()
            .warn?.(
              `[${accountId}] PulseBoard pairing reply failed for ${senderId}: ${String(err)}`,
            );
        },
      });
    },
    onBlocked: ({ senderId, reason }) => {
      runtime.logging
        .getChildLogger()
        .debug?.(`[${accountId}] blocked PulseBoard sender ${senderId} (${reason})`);
    },
  });

  const handleMessage = async (event: PulseBoardMessageEvent) => {
    if (event.type === "dm") {
      // DM inbound: gate through the pre-crypto authorizer first.
      const authorized = await authorizeSender({
        senderId: event.senderId,
        reply: async (text) => {
          const client = activeClients.get(accountId);
          if (client) {
            await client.sendDm(event.senderId, text);
          }
        },
      });
      if (!authorized) {
        return;
      }

      const resolvedAccess = await resolveInboundAccess(event.senderId, event.text);
      if (resolvedAccess.access.decision !== "allow") {
        runtime.logging
          .getChildLogger()
          .warn?.(
            `[${accountId}] dropping PulseBoard DM from ${event.senderId} (${resolvedAccess.access.reason})`,
          );
        return;
      }

      await dispatchInboundDirectDmWithRuntime({
        cfg: config,
        runtime,
        channel: "pulseboard",
        channelLabel: "PulseBoard",
        accountId,
        peer: { kind: "direct", id: event.senderId },
        senderId: event.senderId,
        senderAddress: `pulseboard:${event.senderId}`,
        recipientAddress: `pulseboard:${account.userId}`,
        conversationLabel: event.senderName ?? event.senderId,
        rawBody: event.text,
        messageId: event.messageId,
        timestamp: event.timestamp,
        commandAuthorized: resolvedAccess.commandAuthorized,
        deliver: async (payload) => {
          const outboundText =
            payload && typeof payload === "object" && "text" in payload
              ? String((payload as { text?: string }).text ?? "")
              : "";
          if (!outboundText.trim()) {
            return;
          }
          const tableMode = runtime.channel.text.resolveMarkdownTableMode({
            cfg: config,
            channel: "pulseboard",
            accountId,
          });
          const client = activeClients.get(accountId);
          if (client) {
            await client.sendDm(
              event.senderId,
              runtime.channel.text.convertMarkdownTables(outboundText, tableMode),
            );
          }
        },
        onRecordError: (err) => {
          runtime.logging
            .getChildLogger()
            .error(`[${accountId}] failed recording PulseBoard DM session: ${String(err)}`);
        },
        onDispatchError: (err, info) => {
          runtime.logging
            .getChildLogger()
            .error(`[${accountId}] PulseBoard DM ${info.kind} reply failed: ${String(err)}`);
        },
      });
    } else {
      // Board (group) inbound: check board access policy before dispatching.
      const groupPolicy = account.config.groupPolicy ?? "allowlist";
      if (groupPolicy === "disabled") {
        return;
      }
      if (groupPolicy === "allowlist") {
        const boardGroupAllowFrom = account.config.groupAllowFrom ?? [];
        if (
          boardGroupAllowFrom.length > 0 &&
          !isPulseBoardSenderAllowed(event.senderId, boardGroupAllowFrom.map(String))
        ) {
          return;
        }
      }

      await handleBoardInbound({
        event: event as PulseBoardMessageEvent & { type: "board" },
        accountId,
        cfg: config,
        deliver: async (boardId, text) => {
          const client = activeClients.get(accountId);
          if (client) {
            await client.postToBoard(boardId, text);
          }
        },
      });
    }
  };

  const client = await connectPulseBoard({
    apiKey: account.apiKey,
    abortSignal,
    onConnect: () => {
      runtime.logging
        .getChildLogger()
        .info(`[${accountId}] PulseBoard connected (userId: ${account.userId})`);
    },
    onDisconnect: () => {
      runtime.logging.getChildLogger().info(`[${accountId}] PulseBoard disconnected`);
    },
    onError: (err, ctx) => {
      runtime.logging
        .getChildLogger()
        .error(`[${accountId}] PulseBoard error (${ctx}): ${err.message}`);
    },
    onMessage: handleMessage,
  });

  activeClients.set(accountId, client);

  // Hold until the abort signal fires.
  await new Promise<void>((resolve) => {
    if (abortSignal.aborted) {
      resolve();
      return;
    }
    abortSignal.addEventListener("abort", () => {
      activeClients.delete(accountId);
      resolve();
    });
  });
}

