import { describe, expect, it } from "vitest";
import { pulseBoardPlugin } from "./channel.js";
import {
  isBoardTarget,
  looksLikePulseBoardId,
  normalizePulseBoardAllowEntry,
  normalizePulseBoardTarget,
} from "./normalize.js";
import { listPulseBoardAccountIds, resolvePulseBoardAccount } from "./types.js";

// ── normalizePulseBoardTarget ─────────────────────────────────────────

describe("normalizePulseBoardTarget", () => {
  it("returns a plain user ID unchanged", () => {
    expect(normalizePulseBoardTarget("alice")).toBe("alice");
  });

  it("strips the user: prefix", () => {
    expect(normalizePulseBoardTarget("user:bob")).toBe("bob");
  });

  it("strips the pulseboard: prefix", () => {
    expect(normalizePulseBoardTarget("pulseboard:charlie")).toBe("charlie");
  });

  it("strips the board: prefix", () => {
    expect(normalizePulseBoardTarget("board:general")).toBe("general");
  });

  it("normalizes a hyphenated board slug", () => {
    expect(normalizePulseBoardTarget("general-chat")).toBe("general-chat");
  });

  it("strips pulseboard: + board: combined prefix", () => {
    expect(normalizePulseBoardTarget("pulseboard:board:ops")).toBe("ops");
  });

  it("lower-cases the input", () => {
    expect(normalizePulseBoardTarget("Alice")).toBe("alice");
  });

  it("returns undefined for an empty string", () => {
    expect(normalizePulseBoardTarget("")).toBeUndefined();
  });

  it("returns undefined for whitespace-only input", () => {
    expect(normalizePulseBoardTarget("   ")).toBeUndefined();
  });
});

// ── isBoardTarget ─────────────────────────────────────────────────────

describe("isBoardTarget", () => {
  it("identifies a hyphenated slug as a board", () => {
    expect(isBoardTarget("general-chat")).toBe(true);
  });

  it("identifies a plain user ID as NOT a board", () => {
    expect(isBoardTarget("alice")).toBe(false);
  });

  it("identifies a board: prefixed target as a board", () => {
    // After normalization the prefix is stripped, but if someone passes
    // "board:announcements" the hyphen check fires on "board:" prefix.
    expect(isBoardTarget("board:announcements")).toBe(true);
  });

  it("identifies an underscore user ID as NOT a board", () => {
    expect(isBoardTarget("alice_99")).toBe(false);
  });

  it("identifies a single-word board name without a hyphen as NOT a board", () => {
    // e.g. "announcements" — no hyphen, no board: prefix → treated as a user ID
    expect(isBoardTarget("announcements")).toBe(false);
  });
});

// ── looksLikePulseBoardId ─────────────────────────────────────────────

describe("looksLikePulseBoardId", () => {
  it("returns true for a plain user ID", () => {
    expect(looksLikePulseBoardId("alice")).toBe(true);
  });

  it("returns true for a board slug", () => {
    expect(looksLikePulseBoardId("general-chat")).toBe(true);
  });

  it("returns true for a prefixed ID", () => {
    expect(looksLikePulseBoardId("user:alice")).toBe(true);
  });

  it("returns false for an empty string", () => {
    expect(looksLikePulseBoardId("")).toBe(false);
  });

  it("returns false for a URL-like string", () => {
    expect(looksLikePulseBoardId("https://example.com/user")).toBe(false);
  });
});

// ── normalizePulseBoardAllowEntry ─────────────────────────────────────

describe("normalizePulseBoardAllowEntry", () => {
  it("passes '*' through unchanged", () => {
    expect(normalizePulseBoardAllowEntry("*")).toBe("*");
  });

  it("strips user: prefix and lower-cases", () => {
    expect(normalizePulseBoardAllowEntry("user:Alice")).toBe("alice");
  });

  it("strips pulseboard: prefix", () => {
    expect(normalizePulseBoardAllowEntry("pulseboard:bob")).toBe("bob");
  });

  it("returns empty string for empty input", () => {
    expect(normalizePulseBoardAllowEntry("")).toBe("");
  });
});

// ── resolvePulseBoardAccount ──────────────────────────────────────────

describe("resolvePulseBoardAccount", () => {
  it("returns configured=false when no apiKey is set", () => {
    const account = resolvePulseBoardAccount({ cfg: {} });
    expect(account.configured).toBe(false);
    expect(account.apiKey).toBe("");
  });

  it("returns configured=true when an apiKey is present", () => {
    const account = resolvePulseBoardAccount({
      cfg: { channels: { pulseboard: { apiKey: "pb-secret-key-123" } } },
    });
    expect(account.configured).toBe(true);
    expect(account.apiKey).toBe("pb-secret-key-123");
  });

  it("derives userId from the api key when no override is given", () => {
    const account = resolvePulseBoardAccount({
      cfg: { channels: { pulseboard: { apiKey: "ABCDEFGH_extra" } } },
    });
    expect(account.userId).toMatch(/^pb-[a-z0-9]+$/u);
  });

  it("respects an explicit userId override", () => {
    const account = resolvePulseBoardAccount({
      cfg: { channels: { pulseboard: { apiKey: "some-key", userId: "mybot" } } },
    });
    expect(account.userId).toBe("mybot");
  });

  it("returns enabled=false when explicitly disabled", () => {
    const account = resolvePulseBoardAccount({
      cfg: { channels: { pulseboard: { enabled: false, apiKey: "key" } } },
    });
    expect(account.enabled).toBe(false);
  });
});

// ── listPulseBoardAccountIds ──────────────────────────────────────────

describe("listPulseBoardAccountIds", () => {
  it("returns [] when no apiKey is set", () => {
    expect(listPulseBoardAccountIds({})).toEqual([]);
  });

  it("returns ['default'] when an apiKey is present", () => {
    const ids = listPulseBoardAccountIds({
      channels: { pulseboard: { apiKey: "some-key" } },
    });
    expect(ids).toEqual(["default"]);
  });
});

// ── pulseBoardPlugin capabilities & outbound ──────────────────────────

describe("pulseBoardPlugin", () => {
  it("declares both direct and group chat types", () => {
    expect(pulseBoardPlugin.capabilities.chatTypes).toContain("direct");
    expect(pulseBoardPlugin.capabilities.chatTypes).toContain("group");
  });

  it("has a 4000-character text chunk limit", () => {
    expect(pulseBoardPlugin.outbound?.textChunkLimit).toBe(4000);
  });

  it("uses the pulseboard channel ID", () => {
    expect(pulseBoardPlugin.id).toBe("pulseboard");
  });

  it("is not media-capable", () => {
    expect(pulseBoardPlugin.capabilities.media).toBe(false);
  });

  it("does not enable block streaming", () => {
    expect(pulseBoardPlugin.capabilities.blockStreaming).toBe(false);
  });
});

