import { describeAccountSnapshot } from "openclaw/plugin-sdk/account-helpers";
import {
  createScopedDmSecurityResolver,
  createTopLevelChannelConfigAdapter,
} from "openclaw/plugin-sdk/channel-config-helpers";
import { createChannelPairingController } from "openclaw/plugin-sdk/channel-pairing";
import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import {
  buildChannelOutboundSessionRoute,
  createChatChannelPlugin,
  formatPairingApproveHint,
  stripChannelTargetPrefix,
  type ChannelOutboundSessionRouteParams,
} from "openclaw/plugin-sdk/core";
import {
  buildPassiveChannelStatusSummary,
  buildTrafficStatusSummary,
  runStoppablePassiveMonitor,
} from "openclaw/plugin-sdk/extension-shared";
import {
  createComputedAccountStatusAdapter,
  createDefaultChannelRuntimeState,
  collectStatusIssuesFromLastError,
} from "openclaw/plugin-sdk/status-helpers";
import {
  buildChannelConfigSchema,
  PAIRING_APPROVED_MESSAGE,
  type ChannelPlugin,
} from "../runtime-api.js";
import { PulseBoardConfigSchema } from "./config-schema.js";
import { monitorPulseBoardProvider } from "./monitor.js";
import {
  isBoardTarget,
  looksLikePulseBoardId,
  normalizePulseBoardAllowEntry,
  normalizePulseBoardTarget,
} from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import { activeClients, sendMessagePulseBoard } from "./send.js";
import { pulseBoardSetupAdapter, pulseBoardSetupWizard } from "./setup-surface.js";
import {
  listPulseBoardAccountIds,
  resolvePulseBoardAccount,
  resolveDefaultPulseBoardAccountId,
  type CoreConfig,
  type ResolvedPulseBoardAccount,
} from "./types.js";

// ── Outbound session route resolution ────────────────────────────────

function resolvePulseBoardOutboundSessionRoute(
  params: ChannelOutboundSessionRouteParams,
): ReturnType<typeof buildChannelOutboundSessionRoute> | null {
  const target = stripChannelTargetPrefix(params.target, "pulseboard");
  if (!target) {
    return null;
  }
  const normalized = normalizePulseBoardTarget(target);
  if (!normalized) {
    return null;
  }
  const isBoard = isBoardTarget(normalized);
  return buildChannelOutboundSessionRoute({
    cfg: params.cfg,
    agentId: params.agentId,
    channel: "pulseboard",
    accountId: params.accountId,
    peer: { kind: isBoard ? "group" : "direct", id: normalized },
    chatType: isBoard ? "group" : "direct",
    from: isBoard ? `pulseboard:board:${normalized}` : `pulseboard:${normalized}`,
    to: isBoard ? `pulseboard:board:${normalized}` : `pulseboard:${normalized}`,
  });
}

// ── Config adapter ────────────────────────────────────────────────────

const pulseBoardConfigAdapter = createTopLevelChannelConfigAdapter<ResolvedPulseBoardAccount>({
  sectionKey: "pulseboard",
  resolveAccount: (cfg) => resolvePulseBoardAccount({ cfg }),
  listAccountIds: listPulseBoardAccountIds,
  defaultAccountId: resolveDefaultPulseBoardAccountId,
  deleteMode: "clear-fields",
  clearBaseFields: ["name", "defaultAccount", "apiKey", "userId", "dmPolicy", "allowFrom"],
  resolveAllowFrom: (account) => account.config.allowFrom,
  formatAllowFrom: (allowFrom) =>
    allowFrom
      .map((entry) => String(entry).trim())
      .filter(Boolean)
      .map((entry) => normalizePulseBoardAllowEntry(entry))
      .filter(Boolean),
});

// ── DM security resolver ──────────────────────────────────────────────

const resolvePulseBoardDmPolicy = createScopedDmSecurityResolver<ResolvedPulseBoardAccount>({
  channelKey: "pulseboard",
  resolvePolicy: (account) => account.config.dmPolicy,
  resolveAllowFrom: (account) => account.config.allowFrom,
  policyPathSuffix: "dmPolicy",
  defaultPolicy: "pairing",
  approveHint: formatPairingApproveHint("pulseboard"),
  normalizeEntry: (raw) => normalizePulseBoardAllowEntry(raw),
});

// ── Main plugin definition ────────────────────────────────────────────

export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard",
      docsPath: "/channels/pulseboard",
      docsLabel: "pulseboard",
      blurb: "Real-time bulletin boards and DMs",
      order: 60,
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
      blockStreaming: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    configSchema: buildChannelConfigSchema(PulseBoardConfigSchema),
    setup: pulseBoardSetupAdapter,
    setupWizard: pulseBoardSetupWizard,
    config: {
      ...pulseBoardConfigAdapter,
      isConfigured: (account) => account.configured,
      describeAccount: (account) =>
        describeAccountSnapshot({
          account,
          configured: account.configured,
          extra: { userId: account.userId },
        }),
    },
    messaging: {
      normalizeTarget: (target) => normalizePulseBoardTarget(target) ?? null,
      targetResolver: {
        looksLikeId: looksLikePulseBoardId,
        hint: "<userId|board:boardName|board-name>",
      },
      resolveOutboundSessionRoute: (params) => resolvePulseBoardOutboundSessionRoute(params),
    },
    groups: {
      resolveRequireMention: ({ cfg, accountId, groupId }) => {
        const account = resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId });
        if (!groupId) {
          return true;
        }
        const boardCfg = account.config.boards?.[groupId];
        return boardCfg?.requireMention ?? true;
      },
      resolveToolPolicy: ({ cfg, accountId, groupId }) => {
        if (!groupId) {
          return undefined;
        }
        // Per-board tool policy is not yet modeled — return undefined to use the global default.
        return undefined;
      },
    },
    status: createComputedAccountStatusAdapter<ResolvedPulseBoardAccount>({
      defaultRuntime: createDefaultChannelRuntimeState("default"),
      collectStatusIssues: (accounts) =>
        collectStatusIssuesFromLastError("pulseboard", accounts),
      buildChannelSummary: ({ snapshot }) =>
        buildPassiveChannelStatusSummary(snapshot, {
          userId: (snapshot.extra as { userId?: string } | undefined)?.userId ?? null,
        }),
      resolveAccountSnapshot: ({ account, runtime }) => ({
        accountId: account.accountId,
        name: account.name,
        enabled: account.enabled,
        configured: account.configured,
        extra: { userId: account.userId, ...buildTrafficStatusSummary(runtime) },
      }),
    }),
    gateway: {
      startAccount: async (ctx) => {
        const account = ctx.account;
        if (!account.configured) {
          throw new Error(
            `PulseBoard is not configured for account "${account.accountId}" — add channels.pulseboard.apiKey.`,
          );
        }
        ctx.log?.info(
          `[${account.accountId}] starting PulseBoard provider (userId: ${account.userId})`,
        );
        const runtime = getPulseBoardRuntime();
        const pairing = createChannelPairingController({
          core: runtime,
          channel: "pulseboard",
          accountId: account.accountId,
        });
        // Expose pairing.readStoreForDmPolicy via runtime so the inbound handler can read it.
        // (Stored on the runtime ref; monitor.ts creates its own controller.)
        void pairing;
        await runStoppablePassiveMonitor({
          abortSignal: ctx.abortSignal,
          start: async () =>
            monitorPulseBoardProvider({
              accountId: account.accountId,
              config: ctx.cfg as CoreConfig,
              abortSignal: ctx.abortSignal,
            }),
        });
      },
    },
  },
  pairing: {
    text: {
      idLabel: "pulseBoardUser",
      message: PAIRING_APPROVED_MESSAGE,
      normalizeAllowEntry: (entry) => normalizePulseBoardAllowEntry(entry),
      notify: async ({ id, message }) => {
        await sendMessagePulseBoard(id, message);
      },
    },
  },
  security: {
    resolveDmPolicy: resolvePulseBoardDmPolicy,
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ cfg, to, text, accountId }) => {
      const aid = accountId ?? undefined;
      const runtime = getPulseBoardRuntime();
      const tableMode = runtime.channel.text.resolveMarkdownTableMode({
        cfg,
        channel: "pulseboard",
        accountId: aid,
      });
      const normalized = normalizePulseBoardTarget(to);
      if (!normalized) {
        throw new Error(`Invalid PulseBoard target: ${JSON.stringify(to)}`);
      }
      const client = activeClients.get(aid ?? "default");
      if (!client) {
        throw new Error(`PulseBoard client not running for account "${aid ?? "default"}"`);
      }
      const message = runtime.channel.text.convertMarkdownTables(text ?? "", tableMode);
      let messageId: string;
      if (isBoardTarget(normalized)) {
        const result = await client.postToBoard(normalized, message);
        messageId = result.messageId;
      } else {
        const result = await client.sendDm(normalized, message);
        messageId = result.messageId;
      }
      return attachChannelToResult("pulseboard", { to: normalized, messageId });
    },
  },
});

