/**
 * Fictional PulseBoard API client stub.
 *
 * In a real implementation this module would open a WebSocket connection to the
 * PulseBoard service, authenticate with the API key, and stream inbound events.
 * Here every operation is stubbed out so the plugin compiles and the structural
 * tests pass without a live server.
 */

export interface PulseBoardMessageEvent {
  type: "dm" | "board";
  messageId: string;
  senderId: string;
  senderName?: string;
  /** Only set when type === "board". */
  boardId?: string;
  text: string;
  timestamp: number;
}

export type PulseBoardMessageHandler = (event: PulseBoardMessageEvent) => Promise<void>;
export type PulseBoardErrorHandler = (error: Error, context: string) => void;

export interface PulseBoardClientHandle {
  /** Send a direct message to a user. */
  sendDm(userId: string, text: string): Promise<{ messageId: string }>;
  /** Post a message to a named board. */
  postToBoard(boardId: string, text: string): Promise<{ messageId: string }>;
  /** Close the connection and stop receiving events. */
  close(): void;
}

/**
 * Connect to PulseBoard and start receiving messages.
 *
 * @param opts.apiKey       - PulseBoard API key used to authenticate.
 * @param opts.onMessage    - Called for every inbound DM or board event.
 * @param opts.onError      - Called when a transport error occurs.
 * @param opts.onConnect    - Called once the connection is established.
 * @param opts.onDisconnect - Called when the connection drops.
 * @param opts.abortSignal  - When aborted the connection is closed gracefully.
 */
export async function connectPulseBoard(opts: {
  apiKey: string;
  onMessage: PulseBoardMessageHandler;
  onError: PulseBoardErrorHandler;
  onConnect: () => void;
  onDisconnect: () => void;
  abortSignal: AbortSignal;
}): Promise<PulseBoardClientHandle> {
  // Stub: immediately signal a successful connection and return a no-op handle.
  opts.onConnect();

  const handle: PulseBoardClientHandle = {
    async sendDm(userId, text) {
      // Stub: real implementation would POST to the PulseBoard API.
      return { messageId: `pb-dm-${Date.now()}-${userId.slice(0, 4)}` };
    },
    async postToBoard(boardId, text) {
      // Stub: real implementation would POST to the PulseBoard API.
      return { messageId: `pb-board-${Date.now()}-${boardId.slice(0, 4)}` };
    },
    close() {
      opts.onDisconnect();
    },
  };

  opts.abortSignal.addEventListener("abort", () => {
    handle.close();
  });

  return handle;
}

/**
 * Derive a stable userId from an API key.
 *
 * Takes the first 8 characters of the key, strips non-alphanumeric characters,
 * and prepends "pb-" to produce a deterministic but opaque identifier.
 */
export function resolveUserIdFromApiKey(apiKey: string): string {
  const fragment = apiKey.slice(0, 8).toLowerCase().replace(/[^a-z0-9]/g, "");
  return `pb-${fragment || "user"}`;
}

import {
  AllowFromListSchema,
  buildChannelConfigSchema,
  DmPolicySchema,
  GroupPolicySchema,
  MarkdownConfigSchema,
  ReplyRuntimeConfigSchemaShape,
} from "openclaw/plugin-sdk/channel-config-primitives";
import { buildSecretInputSchema } from "openclaw/plugin-sdk/secret-input";
import { z } from "openclaw/plugin-sdk/zod";

/** Per-board Zod schema. */
const PulseBoardBoardSchema = z
  .object({
    enabled: z.boolean().optional(),
    allowFrom: AllowFromListSchema,
    requireMention: z.boolean().optional(),
    systemPrompt: z.string().optional(),
  })
  .strict();

/** Full Zod schema for channels.pulseboard.* configuration. */
export const PulseBoardConfigSchema = z
  .object({
    /** Whether this channel is enabled. */
    enabled: z.boolean().optional(),

    /** Optional display name for this account. */
    name: z.string().optional(),

    /** Optional default account id for routing. */
    defaultAccount: z.string().optional(),

    /** PulseBoard API key (literal or env-var reference). */
    apiKey: buildSecretInputSchema().optional(),

    /** Optional userId override; derived from the API key when absent. */
    userId: z.string().optional(),

    /** DM access policy. Defaults to "pairing". */
    dmPolicy: DmPolicySchema.optional(),

    /** Allowed DM sender IDs. */
    allowFrom: AllowFromListSchema,

    /** Board access policy. Defaults to "allowlist". */
    groupPolicy: GroupPolicySchema.optional(),

    /** Allowed board sender IDs (used when groupPolicy is "allowlist"). */
    groupAllowFrom: AllowFromListSchema,

    /** Per-board configuration keyed by board ID slug. */
    boards: z.record(z.string(), PulseBoardBoardSchema.optional()).optional(),

    /** Markdown table rendering overrides. */
    markdown: MarkdownConfigSchema,

    ...ReplyRuntimeConfigSchemaShape,
  })
  .strict();

export type PulseBoardConfig = z.infer<typeof PulseBoardConfigSchema>;

/**
 * JSON Schema for Control UI (converted from Zod).
 */
export const pulseBoardChannelConfigSchema = buildChannelConfigSchema(PulseBoardConfigSchema);

