/**
 * Target normalization utilities for PulseBoard.
 *
 * PulseBoard distinguishes two kinds of targets:
 *   - Users: alphanumeric IDs (e.g. "alice", "user:bob")
 *   - Boards: slug-style IDs (e.g. "board:announcements", "general-chat")
 *
 * The "board:" prefix explicitly marks a target as a board. A slug that
 * contains a hyphen (e.g. "general-chat") is also treated as a board name.
 * Plain lowercase alphanumeric strings without hyphens are user IDs.
 */

const BOARD_PREFIX = "board:";
const USER_PREFIX = "user:";
const CHANNEL_PREFIX = "pulseboard:";

/** Slug pattern: lowercase alphanumeric with optional internal hyphens. */
const SLUG_PATTERN = /^[a-z0-9]+(?:-[a-z0-9]+)*$/u;

/** User ID pattern: lowercase alphanumeric only (no hyphens). */
const USER_ID_PATTERN = /^[a-z0-9_]+$/u;

/**
 * Return true when the (already-normalized, prefix-stripped) target looks like
 * a board slug rather than a user ID.
 *
 * Decision rules (applied after prefix stripping):
 *   1. Starts with "board:" → board
 *   2. Contains a hyphen → board (slugs use hyphens; user IDs do not)
 *   3. Otherwise → user ID
 */
export function isBoardTarget(target: string): boolean {
  const stripped = stripAllPrefixes(target);
  return stripped.startsWith(BOARD_PREFIX) || stripped.includes("-");
}

/**
 * Normalize a raw PulseBoard target string.
 * Returns `undefined` when the input is not a recognizable PulseBoard target.
 *
 * Examples:
 *   "alice"                 → "alice"
 *   "user:alice"            → "alice"
 *   "pulseboard:alice"      → "alice"
 *   "board:general"         → "general"
 *   "pulseboard:board:ops"  → "ops"
 *   "general-chat"          → "general-chat"
 *   ""                      → undefined
 */
export function normalizePulseBoardTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) {
    return undefined;
  }
  const stripped = stripAllPrefixes(trimmed.toLowerCase());
  if (!stripped) {
    return undefined;
  }
  if (!SLUG_PATTERN.test(stripped) && !USER_ID_PATTERN.test(stripped)) {
    return undefined;
  }
  return stripped;
}

/**
 * Return true when `input` looks like a PulseBoard ID (user or board).
 * Used by the messaging targetResolver to decide whether to attempt resolution.
 */
export function looksLikePulseBoardId(input: string): boolean {
  const trimmed = input.trim().toLowerCase();
  if (!trimmed) {
    return false;
  }
  const stripped = stripAllPrefixes(trimmed);
  return SLUG_PATTERN.test(stripped) || USER_ID_PATTERN.test(stripped);
}

/**
 * Normalize an allowFrom entry to a canonical lowercase ID.
 * Strips known prefixes and trims whitespace.
 * Returns the wildcard "*" unchanged.
 */
export function normalizePulseBoardAllowEntry(raw: string): string {
  const trimmed = raw.trim();
  if (!trimmed || trimmed === "*") {
    return trimmed;
  }
  return stripAllPrefixes(trimmed.toLowerCase());
}

// ── Internal helpers ─────────────────────────────────────────────────

/** Strip leading pulseboard:, user:, and board: prefixes (in that order). */
function stripAllPrefixes(value: string): string {
  let s = value;
  if (s.startsWith(CHANNEL_PREFIX)) {
    s = s.slice(CHANNEL_PREFIX.length);
  }
  if (s.startsWith(BOARD_PREFIX)) {
    s = s.slice(BOARD_PREFIX.length);
  }
  if (s.startsWith(USER_PREFIX)) {
    s = s.slice(USER_PREFIX.length);
  }
  return s;
}

