 * Examples:
 *   "alice"                 → "alice"
 *   "user:alice"            → "alice"
 *   "pulseboard:alice"      → "alice"
 *   "board:general"         → "general"
 *   "pulseboard:board:ops"  → "ops"
 *   "general-chat"          → "general-chat"
 *   ""                      → undefined
 */
export function normalizePulseBoardTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) {
    return undefined;
  }
  const stripped = stripAllPrefixes(trimmed.toLowerCase());
  if (!stripped) {
    return undefined;
  }
  if (!SLUG_PATTERN.test(stripped) && !USER_ID_PATTERN.test(stripped)) {
    return undefined;
  }
  return stripped;
}

/**
 * Return true when `input` looks like a PulseBoard ID (user or board).
 * Used by the messaging targetResolver to decide whether to attempt resolution.
 */
export function looksLikePulseBoardId(input: string): boolean {
  const trimmed = input.trim().toLowerCase();
  if (!trimmed) {
    return false;
  }
  const stripped = stripAllPrefixes(trimmed);
  return SLUG_PATTERN.test(stripped) || USER_ID_PATTERN.test(stripped);
}

/**
 * Normalize an allowFrom entry to a canonical lowercase ID.
 * Strips known prefixes and trims whitespace.
 * Returns the wildcard "*" unchanged.
 */
export function normalizePulseBoardAllowEntry(raw: string): string {
  const trimmed = raw.trim();
  if (!trimmed || trimmed === "*") {
    return trimmed;
  }
  return stripAllPrefixes(trimmed.toLowerCase());
}

// ── Internal helpers ─────────────────────────────────────────────────

/** Strip leading pulseboard:, user:, and board: prefixes (in that order). */
function stripAllPrefixes(value: string): string {
  let s = value;
  if (s.startsWith(CHANNEL_PREFIX)) {
    s = s.slice(CHANNEL_PREFIX.length);
  }
  if (s.startsWith(BOARD_PREFIX)) {
    s = s.slice(BOARD_PREFIX.length);
  }
  if (s.startsWith(USER_PREFIX)) {
    s = s.slice(USER_PREFIX.length);
  }
  return s;
}

